args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT DISTINCT ?birthMonth
WHERE {
  ?stage wdt:P1545 wd:Q4621554;
         wdt:P2203 "1";
         wdt:P4146 ?rider.
  ?rider wdt:P1844 ?team.
  ?team wdt:P571 ?founded.
  FILTER (year(?founded) = 2000).
  ?rider wdt:P569 ?birthDate.
  BIND(month(?birthDate) AS ?birthMonth)
}
